body:
In following code one index of the packed array is assigned with continuous assignment, while others are driven by always_ff process
However the error is generated

This behavior is supported in Vivado (both simulation and synthesis) and Questasim
```
// Buffer to store head
logic [HEAD_SIZE_WORDS:0][TDATA_WIDTH-1:0] head_buf;

assign head_buf[HEAD_SIZE_WORDS] = stage_2_pkt_i.tdata;

always_ff @(posedge clk_i) begin
   // If it's pending, it's not moving
   if (stage_2_pkt_i.tvalid && !stage_2_i.extend_packet && stage_2_pkt_i.tready && !pending_head) begin
      for (int i = 1; i <= HEAD_SIZE_WORDS; i++) begin
         head_buf[i-1] <= head_buf[i];
      end
   end
end
```

Other example is with packed struct, which fields can be driven differently
In this case struct is used to avoid concatenation syntax to pass all signals through a pipeline
```
typedef struct packed {
   logic                   tail_tlast_in_head_word;
   logic [TDATA_WIDTH-1:0] tdata_prev;
   logic [TKEEP_WIDTH-1:0] tkeep_prev;
   logic [TKEEP_WIDTH-1:0] tstrb_prev;
   logic                   extend_packet;
   logic                   merge_tlast;
   logic                   head_end_flag;
   logic                   head_end_event;
   logic                   error_event;
   error_t                 error;
   logic                   tfirst;
} stage_1_sideband_t;

assign stage_1_o.head_end_event = stage_1_o.tfirst && stage_1_pkt_i.tvalid;

// Locks the value of head_end_event, signalling that tail can be outputed
always_ff @(posedge clk_i) begin
   if (rst_i) begin
      stage_1_o.head_end_flag <= 1'b0;
   end else begin
      if (stage_1_pkt_i.tvalid && stage_1_pkt_i.tready) begin
         if (stage_1_pkt_i.tlast) begin
            stage_1_o.head_end_flag <= 1'b0;
         end else begin
            if (stage_1_o.head_end_event) begin
               stage_1_o.head_end_flag <= 1'b1;
            end
         end
      end
   end
end
```
